scwin._getInputComp = function (id) {
    if (!id || id === "") return null;
    try {
        return $p.getComponentById(id);
    } catch (e) {
        return null;
    }
};

scwin._getInputValue = function (id) {
    let comp = scwin._getInputComp(id);
    if (comp) return comp.getValue();
    return "";
};

scwin._setInputValue = function (id, val) {
    let comp = scwin._getInputComp(id);
    if (comp) comp.setValue(val);
};

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function () {

};

scwin.onUdcCompleted = function () {
    ed_bilgLoofcCd.focus();

    $c.gus.cfDisableAllBtn();
    $c.gus.cfDisableObjects([btn_addRow, btn_cancelRow]);

    document.addEventListener('keydown', scwin.gr_line_tabCapture, true);
};

//-------------------------------------------------------------------------
// 조건에 따라 DataSet 가져오기
//-------------------------------------------------------------------------
scwin.f_GetDataSet = async function (condition, row) {
    // 조회 조건 이전 데이터 삭제
    dma_linelist_con.setJSON([]);
    dma_billtitle_con.setJSON([]);

    // LINE DataSet
    if (condition == "LINE_CON") {
        dma_linelist_con.set("bilgLoofcCd", ed_bilgLoofcCd.getValue());
        dma_linelist_con.set("bilgComnCdKnd", scwin.billtitle);

        sbm_linelist_retrieve.action = "/ds.fs.bilg.bilgcomncdmgnt.RetrieveBillingComnCdLineListCMD.do";
        await $c.sbm.execute(sbm_linelist_retrieve);

    } else if (condition == "BILGCOMNCD_CON") {
        dma_billtitle_con.set("bilgLoofcCd", ds_linelist.getCellData(0, "bilgLoofcCd"));
        dma_billtitle_con.set("lineCd", ds_linelist.getCellData(parseInt(row), "lineCd"));
        dma_billtitle_con.set("bilgComnCdKnd", scwin.billtitle);

        // BILL TITLE DataSet(공통코드) >> 두 URL 동일함.
        if (row == "0") {
            sbm_billtitle_retrieve.action = "/ds.fs.bilg.bilgcomncdmgnt.RetrieveBillTitleListCMD.do";
        } else {
            // BILL TITLE DataSet(해당코드)
            sbm_billtitle_retrieve.action = "/ds.fs.bilg.bilgcomncdmgnt.RetrieveBillTitleListCMD.do";
        }
        await $c.sbm.execute(sbm_billtitle_retrieve);
    }
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    let chk = await $c.gus.cfValidate([ed_bilgLoofcCd]);
    if (!chk) return;

    await scwin.f_GetDataSet("LINE_CON");
};

scwin.btn_retrieve_onclick = function (e) {
    scwin.f_Retrieve();
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
    let chk = await $c.gus.cfValidate([gr_line], null, true);
    if (!chk) return;

    // 필수입력항목 체크
    if (!(await scwin.f_CheckMandatory())) return;

    let confirmChk = await $c.win.confirm(MSG_CM_CRM_001);
    if (!confirmChk) return;

    let rowPos = ds_linelist.getRowPosition();
    for (let j = 0; j < ds_billtitle.getRowCount(); j++) {
        ds_billtitle.setCellData(j, "bilgLoofcCd", ds_linelist.getCellData(0, "bilgLoofcCd"));
        ds_billtitle.setCellData(j, "lineCd", ds_linelist.getCellData(rowPos, "lineCd"));

        let ids = scwin.titleInputIds[j];
        if (ids) {
            ds_billtitle.setCellData(j, "title1", scwin._getInputValue(ids[0]));
            ds_billtitle.setCellData(j, "title2", scwin._getInputValue(ids[1]));
            ds_billtitle.setCellData(j, "title3", scwin._getInputValue(ids[2]));
            ds_billtitle.setCellData(j, "title4", scwin._getInputValue(ids[3]));
            ds_billtitle.setCellData(j, "billAggrNm", scwin._getInputValue(ids[4]));
        }
    }

    scwin.delflag = "";

    // 신규입력
    if (scwin.addflag == "REG") {
        sbm_billtitle_save.action = "/ds.fs.bilg.bilgcomncdmgnt.RegistBillTitleCMD.do";
        sbm_billtitle_save.ref = 'data:json,[{"id":"ds_billtitle","key":"IN_DS1"}]';
    } else if (scwin.addflag == "" || scwin.addflag == "MOD") {
        sbm_billtitle_save.action = "/ds.fs.bilg.bilgcomncdmgnt.UpdateBillTitleCMD.do";
        sbm_billtitle_save.ref = 'data:json,[{"id":"ds_billtitle","key":"IN_DS1","action":"modified"}]';
    }
    await $c.sbm.execute(sbm_billtitle_save);
};

scwin.btn_save_onclick = function (e) {
    scwin.f_Save();
};

//-------------------------------------------------------------------------
// 그리드 추가
//-------------------------------------------------------------------------
scwin.f_AddRow = async function () {
    let changePossible = await scwin.f_chkPosChange();
    if (!changePossible) return;

    let rowPos = ds_linelist.insertRow();
    gr_line.setFocusedCell(rowPos, "lineCd", true);
    scwin.f_Popup();

    scwin.f_GetDataSet("BILGCOMNCD_CON", "0");

    if (ds_linelist.getRowStatus(rowPos) == "C") {
        scwin.addflag = "REG";

        setTimeout(function () {
            gr_line.setCellInputType(rowPos, "lineCd", {
                inputType: "textImage",
                options: { viewType: "icon" }
            });
        })
    }
};

scwin.f_Cancel = function () {
    let rowPos = ds_linelist.getRowPosition();
    let status = ds_linelist.getRowStatus(rowPos);

    if (status === "C") {
        ds_linelist.removeRow(rowPos);
    }

    scwin.addflag = "MOD";
};

//-------------------------------------------------------------------------
// 삭제
//-------------------------------------------------------------------------
scwin.f_Delete = async function () {
    let rowPos = ds_linelist.getRowPosition();
    if (ds_linelist.getRowStatus(rowPos) == "C") {
        await $c.gus.cfAlertMsg(scwin.MSG_FS_WRN_004);
        return;
    } else {
        if (ds_linelist.getCellData(rowPos, "lineCd") == "0000") {
            await $c.gus.cfAlertMsg(scwin.MSG_FS_WRN_005);
            return;
        }

        let confirmChk = await $c.win.confirm(MSG_CM_CRM_004);
        if (confirmChk == true) {
            ds_linelist.deleteRow(rowPos);

            let btRowPos = ds_billtitle.getRowPosition();
            ds_billtitle.deleteRow(btRowPos);

            scwin.delflag = "DEL";

            sbm_billtitle_save.action = "/ds.fs.bilg.bilgcomncdmgnt.DeleteBillTitleCMD.do";
            sbm_billtitle_save.ref = 'data:json,[{"id":"ds_billtitle","key":"IN_DS1", "action":"removed"}]';

            await $c.sbm.execute(sbm_billtitle_save);
        }
    }
};

scwin.btn_del_onclick = function (e) {
    scwin.f_Delete();
};

// AS-IS도 실제로 입력하지는 못하고 공통코드 팝업만 호출 가능
scwin.f_Editable = function (edit) {
    if (edit == "true") {
        gr_line.setColumnReadOnly("lineCd", true);
        gr_line.setColumnReadOnly("lineNm", true);
    } else {
        gr_line.setColumnReadOnly("lineCd", true);
        gr_line.setColumnReadOnly("lineNm", true);
    }
};

//-------------------------------------------------------------------------
// 필수입력항목 체크
//-------------------------------------------------------------------------
scwin.f_CheckMandatory = async function () {
    for (let i = 0; i < ds_billtitle.getRowCount(); i++) {
        let ids = scwin.titleInputIds[i];
        if (!ids) continue;

        if ((ds_billtitle.getCellData(i, "title1") || "").trim().length > 1) {
            if (scwin._getInputValue(ids[0]).trim().length < 1) {
                await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["TITLE"]);
                let comp = scwin._getInputComp(ids[0]);
                if (comp) comp.focus();
                return false;
            }
        }
        if ((ds_billtitle.getCellData(i, "title2") || "").trim().length > 1) {
            if (scwin._getInputValue(ids[1]).trim().length < 1) {
                await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["TITLE"]);
                let comp = scwin._getInputComp(ids[1]);
                if (comp) comp.focus();
                return false;
            }
        }
        if ((ds_billtitle.getCellData(i, "title3") || "").trim().length > 1) {
            if (scwin._getInputValue(ids[2]).trim().length < 1) {
                await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["TITLE"]);
                let comp = scwin._getInputComp(ids[2]);
                if (comp) comp.focus();
                return false;
            }
        }
        if ((ds_billtitle.getCellData(i, "title4") || "").trim().length > 1) {
            if (scwin._getInputValue(ids[3]).trim().length < 1) {
                await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["TITLE"]);
                let comp = scwin._getInputComp(ids[3]);
                if (comp) comp.focus();
                return false;
            }
        }
        if ((ds_billtitle.getCellData(i, "billAggrNm") || "").trim().length > 1) {
            if (scwin._getInputValue(ids[4]).trim().length < 1) {
                await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["집계표 TITLE"]);
                let comp = scwin._getInputComp(ids[4]);
                if (comp) comp.focus();
                return false;
            }
        }
    }
    return true;
};

//-------------------------------------------------------------------------
// 팝업창 띄우기
//-------------------------
scwin.f_Popup = async function () {
    let pCode = "";
    let pName = "";

    udc_gridline.setSelectId('retrieveLineInfo'); // XML상의 SELECT ID	
    await udc_gridline.cfCommonPopUp(
        scwin.udc_gridline_callbackFunc
        , pCode.trim()					// 화면에서의 ??? Code Element의	Value
        , pName					// 화면에서의 ??? Name Element의	Value
        , 'F'					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
        , null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
        , null					// Title순서	
        , null					// 보여주는 각 컬럼들의 폭	
        , null					// 컬럼중에서 숨기는	컬럼 지정	
        , null					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
        , null					// POP-UP뛰을때 원도우의	사용자 정의	폭
        , null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
        , null					// 윈도우 위치 Y좌표	
        , null					// 윈도우 위치 X좌표
        , null                   // 중복체크여부
        , 'F'                    // 전체검색허용여부
        , null                   // POP-UP Window Title 검색어1,2(각화면에서 변경할경우)
    );
};

//-------------------------------------------------------------------------
// 팝업창 처리
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch) {

    switch (disGubun) {
        case 1:
            // 청구지점코드팝업
            udc_bilgLoofc.setSelectId('retrieveOpDeptCdInfo');
            await udc_bilgLoofc.cfCommonPopUp(
                scwin.udc_bilgLoofc_callbackFunc,
                pCode.trim(),
                pName,
                pClose,
                null, null, null, null, null, null, null, null, null, null,
                pAllSearch,
                null
            );
            break;
        default:
            break;
    }
};

scwin.f_chkOpenCommonPopUp = async function (inObj, pairObj, disGubun, isCode) {
    let chkObj = await $c.gus.cfCanOpenPopup(inObj, pairObj);
    if (!chkObj) return;

    await $c.gus.cfClearPairObj(pairObj);

    let pVal = $c.gus.cfGetValue(inObj);

    if (isCode == null || isCode == true) {
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    } else {
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
};

// 청구지점코드 공통 popup callback
scwin.udc_bilgLoofc_callbackFunc = function (rtnList) {
    if (rtnList != null && rtnList[0] != "N/A") {
        $c.gus.cfSetReturnValue(rtnList, ed_bilgLoofcCd, txt_bilgLoofcNm); // 청구지점코드, 청구지점명
    }
}

// grid Line 코드 공통 popup callback
scwin.udc_gridline_callbackFunc = function (rtnList) {
    let rowPos = ds_linelist.getRowPosition();
    ds_linelist.setCellData(rowPos, "lineCd", "");
    ds_linelist.setCellData(rowPos, "lineNm", "");

    if (rtnList != null && rtnList[0] != "N/A") {
        ds_linelist.setCellData(rowPos, "lineCd", rtnList[0]); // 라인코드
        ds_linelist.setCellData(rowPos, "lineNm", rtnList[1]); // 라인명
    }
}

scwin.udc_bilgLoofc_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_bilgLoofcCd, txt_bilgLoofcNm, 1);
};

scwin.udc_bilgLoofc_onblurNameEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(txt_bilgLoofcNm, ed_bilgLoofcCd, 1, false);
};

scwin.udc_bilgLoofc_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(1, ed_bilgLoofcCd.getValue(), txt_bilgLoofcNm.getValue(), 'F', 'F');
};

//-------------------------------------------------------------------------
// tab 데이터 조회 완료 후 setting 함수
// BILL TITLE DataSet 화면에 세팅하기
//-------------------------------------------------------------------------
scwin.f_SetBilltitleToScreen = function () {
    totalRow2.setValue(ds_billtitle.getRowCount());

    for (let i = 0; i < ds_billtitle.getRowCount(); i++) {
        let ids = scwin.titleInputIds[i];
        if (!ids) continue;
        scwin._setInputValue(ids[0], ds_billtitle.getCellData(i, "title1"));
        scwin._setInputValue(ids[1], ds_billtitle.getCellData(i, "title2"));
        scwin._setInputValue(ids[2], ds_billtitle.getCellData(i, "title3"));
        scwin._setInputValue(ids[3], ds_billtitle.getCellData(i, "title4"));
        scwin._setInputValue(ids[4], ds_billtitle.getCellData(i, "billAggrNm"));
    }
};

// tab 내부 데이터 초기화 함수
scwin.f_ClearTitleInputs = function () {
    for (let i = 0; i < scwin.titleInputIds.length; i++) {
        let ids = scwin.titleInputIds[i];
        for (let k = 0; k < ids.length; k++) {
            scwin._setInputValue(ids[k], "");
        }
    }
};

//-------------------------------------------------------------------------
// sbm_submit 완료
//-------------------------------------------------------------------------
scwin.sbm_linelist_retrieve_submitdone = async function (e) {
    let rowcnt = ds_linelist.getRowCount();
    totalRow1.setValue("0");
    totalRow2.setValue("0");

    if (rowcnt == 0) {
        scwin.f_ClearTitleInputs(); // 조회 결과 0건 일 때 tile 입력 필드 초기화
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        $c.gus.cfDisableAllBtn();
        $c.gus.cfDisableObjects([btn_addRow, btn_cancelRow]);
    } else {
        totalRow1.setValue(rowcnt);
        gr_line.setFocusedCell(0, "lineCd");

        $c.gus.cfEnableAllBtn();
        $c.gus.cfEnableObjects([btn_addRow, btn_cancelRow]);

        scwin.f_Editable("false");
    }
};

scwin.sbm_billtitle_retrieve_submitdone = function (e) {
    scwin.f_ClearTitleInputs();    // 먼저 전체 초기화
    scwin.f_SetBilltitleToScreen();
};

scwin.sbm_billtitle_save_submitdone = async function (e) {
    var result = e.responseJSON?.resultDataSet?.[0];

    if (!result) return;
    if (result.Msg === "SUCC") {
        scwin.addflag = "MOD";
        if (scwin.delflag == "DEL") {
            await $c.gus.cfAlertMsg(MSG_CM_INF_004);
            scwin.f_Retrieve();

        } else {
            // 저장, 수정 이후 재조회 프로세스가 없고, "R" 초기상태로 셋팅
            for (let i = 0; i < ds_linelist.getRowCount(); i++) {
                ds_linelist.modifyRowStatus(i, "R");
                gr_line.setCellInputType(i, "lineCd", {
                    inputType: "text"
                });

            }
            for (let i = 0; i < ds_billtitle.getRowCount(); i++) {
                ds_billtitle.modifyRowStatus(i, "R");
            }

            await $c.gus.cfAlertMsg(MSG_CM_INF_001);
        }
    }
};

//=========================================================================
// 그리드 이벤트 핸들러
//=========================================================================
scwin.gr_line_tabCapture = function (e) {
    if ((e.keyCode || e.which) !== 9) return;
    if (!gr_line.render || !gr_line.render.contains(document.activeElement)) return;
    e.preventDefault();
    e.stopPropagation();
    var focusTab = tac_tabControl1.getSelectedTabID();
    if (focusTab === 'tabs1') {
        ed_input1.focus();
    } else if (focusTab === 'tabs2') {
        ed_input47.focus();
    } else {
        ed_input249.focus();
    }
};

scwin._revertingNode = false;  // 되돌리기 중 재진입 방지용
scwin.gr_line_onrowindexchange = async function (rowIndex, oldRow) {

    if (scwin._revertingNode) return;
    if (ds_linelist.getRowStatus(oldRow) === "C") {
        let chkConfirm = await scwin.f_chkPosChange();
        if (!chkConfirm) {
            // 무한 반복 방지를 위해 _revertingNode flag 사용
            scwin._revertingNode = true;
            // validtion 검증 실패 -> 원래 row로 복귀
            gr_line.setFocusedCell(oldRow, "lineCd");
            scwin._revertingNode = false;

            return false;
        }
    }

    if (rowIndex >= 0) {
        if (ds_linelist.getRowStatus(rowIndex) != "C") {
            await scwin.f_GetDataSet("BILGCOMNCD_CON", rowIndex);
            scwin.f_Editable("false");
            scwin.addflag = "MOD";
        } else {
            scwin.f_Editable("true");
            scwin.addflag = "REG";
        }
    }
};

// 저장되지 않은 row 발생 시 다른 row 진입 불가(alert으로 확인)
scwin.f_chkPosChange = async function () {
    let chkEdit = ds_linelist.getModifiedIndex();
    if (chkEdit.length > 0) {
        let chkConfirm = await $c.win.confirm("저장하지 않은 데이타를 취소하시겠습니까?");
        if (chkConfirm) {
            ds_linelist.removeRows(chkEdit);
        }
        return chkConfirm;
    } else {
        return true;
    }
}

scwin.btn_fieldClear_onclick = function (e) {
    if (e && e.type === "keydown") return;

    ed_bilgLoofcCd.setValue("");
    txt_bilgLoofcNm.setValue("");
};

// 탭 이동 제어를 위한 플래그 변수
scwin.isManualMove = false;
/**
 * 탭이 선택되기 직전에 발생하는 이벤트
 * @param {Number} selectedIndex - 현재 선택되어 있는(떠나려는) 탭 인덱스
 * @param {Number} index - 새로 선택될(이동하려는) 탭 인덱스
 */
scwin.tac_tabControl1_onbeforeselect = function (selectedIndex, index) {
    // 1. 수동 이동 중인 경우(검증 통과 후)에는 이동을 허용
    if (scwin.isManualMove) {
        return true;
    }

    // 2. 일단 false를 반환하여 사용자의 클릭에 의한 자동 이동을 차단
    // 그 다음 비동기 검증 함수를 호출합니다.
    scwin.fn_asyncTabValidation(selectedIndex, index);

    return false;
};

/**
 * 비동기 유효성 검사 및 수동 탭 이동 처리
 * (가우스: f_ViewTab())
 */
scwin.fn_asyncTabValidation = async function (oldIdx, newIdx) {
    if (ds_billtitle.getRowCount() < 1) {
        await $c.gus.cfAlertMsg(scwin.MSG_FS_WRN_006);
        return;
    }

    // 필수 입력항목 체크
    let isOk = await scwin.f_CheckMandatory();

    if (isOk) {
        // 4. 검증 통과 시 플래그를 true로 바꾸고 수동으로 탭 이동 실행
        scwin.isManualMove = true;

        // TabControl의 API를 사용하여 해당 인덱스로 이동 [2]
        // (이 함수 호출 시 다시 onbeforeselect가 발생하지만, 플래그에 의해 위에서 true가 반환됨)
        tac_tabControl1.setSelectedTabIndex(newIdx);

        // 5. 이동 완료 후 플래그 초기화
        scwin.isManualMove = false;
    }
};
